mapper.select:
select ifnull((
           select sum(ifnull(so.total_amount, 0))
           from wms_sale_order so
           where so.status = 'audited'
             and ifnull(so.audit_time, so.create_time) >= #{startTime}
             and ifnull(so.audit_time, so.create_time) < #{endTime}
       ), 0) as saleAmount,
       ifnull((
           select sum(ifnull(fr.amount, 0))
           from fin_receipt fr
           where ifnull(fr.receipt_date, fr.create_time) >= #{startTime}
             and ifnull(fr.receipt_date, fr.create_time) < #{endTime}
       ), 0) as receivedAmount,
       ifnull((
           select sum(ifnull(po.total_amount, 0))
           from wms_purchase_order po
           where po.status in ('1', '2', '3')
             and ifnull(po.purchase_date, po.create_time) >= #{startTime}
             and ifnull(po.purchase_date, po.create_time) < #{endTime}
       ), 0) as purchaseAmount,
       ifnull((
           select sum(ifnull(soi.quantity, 0) * ifnull(mp.cost_price, 0))
           from wms_sale_order_item soi
           join wms_sale_order so on soi.sale_order_id = so.sale_order_id
           left join md_product mp on soi.product_id = mp.product_id
           where so.status = 'audited'
             and ifnull(so.audit_time, so.create_time) >= #{startTime}
             and ifnull(so.audit_time, so.create_time) < #{endTime}
       ), 0) as saleCostAmount
